let fs = require('fs');
module.exports = (fileName, callback) => {
    fs.readFile(fileName,(err, data)=>{
        if(err){
            console.log(`Error reading file`);
        }else{
          //  console.log(`${data}`);
            callback(null, `${data}`);
        }
    });
};
